INSERT INTO `meeting_minutes` (`id`, `date`, `title`, `content`, `assignments`, `created_at`) VALUES
(340, '2026-03-18', '생산 현장 업무 회의록', '○현장 업무 및 자재 관리 현황\n - 물품 배치: 알메주 2번방 사이 배치(익일부터 장담기 작업 실시)\n - 창고 정리: 사무실 창고 미사용 자재 및 외박스 토평창고 이송(금일 용차 발송)\n - 외부 방문: 고철 업체 방문\n - 청국장 생산 일정 조율(청국장 재고 부족)\n - 2호방 폐된장 정화조 처리', '{\"1767886193864\":[\"항아리숙성실(1~8번방)\"],\"1767886110985\":[\"항아리숙성실(1~8번방)\"],\"1767886242826\":[\"항아리숙성실(1~8번방)\"],\"1767886321944\":[\"항아리숙성실(1~8번방)\"],\"1767934281326\":[\"항아리숙성실(1~8번방)\"],\"1767883107605\":[\"사무실\"],\"1767885834789\":[\"사무실\"],\"1767886051326\":[\"사무실\"],\"1768780657172\":[\"사무실\"],\"1767886449701\":[\"2층(콩증자 및 탈분)\"],\"1767934110640\":[\"2층(콩증자 및 탈분)\"],\"1772497624802\":[\"2층(콩증자 및 탈분)\"],\"1767886730545\":[\"2층(콩증자 및 탈분)\"],\"1767885744947\":[\"소금물\"],\"1767886554527\":[\"소금물\"]}', '2026-03-18 09:24:04'),
(341, '2026-03-17', '생산 현장 업무 회의록', '간장 : 이민여, 에리꼬\n장물 : 우\n\n현장 주요 안내 및 점검 사항\n- 된장롤러 구역: 하절기 해충 유입 방지를 위한 플라스틱 덮개 비치 또는 대책 수립 필요\n- 금일 일정: 15시 30분 뿌리산업 점검 대비 현장 정리정돈 및 규정 복장 착용 엄수(청국장포장기계 선연결필요)\n- 위생계 방문: 차주 수요일 참기름 품목변경신고(OEM→직접생산) 관련 시설 실사 예정\n\n[안건 1] 된장 충진 용량 최적화 및 누출 방지\n현황: 병 용량 대비 과충진 및 장물 과다로 인한 끓어넘침 현상 발생\n요청: 된장 충진량 495g 설정(법적 허용 오차 3% 이내) 및 출고 시 장물 최대한 제거 후 포장\n\n[안건 2] 작업 환경 위생 관리 강화\n현황: 하절기 기온 상승에 따른 된장롤러 구역 내 외부 해충 유입 우려\n요청: 세척 및 이동이 용이한 경량 플라스틱 덮개 제작 또는 현장 맞춤형 방충 대책 수립\n\n[안건 3] 생산 품목 변경 신고에 따른 시설 보완\n현황: 참기름 직접 생산 전환으로 인한 관할 위생계 현장 점검 예정\n요청: 시설 기준 부합 여부 사전 자체 점검 및 점검 당일 대응 준비 철저\n\n', '{\"1767886449701\":[\"2층(콩증자 및 탈분)\"],\"1772497624802\":[\"2층(콩증자 및 탈분)\"],\"1767886730545\":[\"2층(콩증자 및 탈분)\"],\"1767934110640\":[\"2층(콩증자 및 탈분)\"],\"1767885950539\":[\"1층(생산)\"],\"1767886110985\":[\"1층(생산)\"],\"1767886193864\":[\"1층(생산)\"],\"1767886242826\":[\"1층(생산)\"],\"1767886321944\":[\"1층(생산)\",\"간장(송주원)\"],\"1767885744947\":[\"고추장\"],\"1767886051326\":[\"사무실\"],\"1768780657172\":[\"사무실\"],\"1767883107605\":[\"사무실\"],\"1767885834789\":[\"사무실\"],\"1767934281326\":[\"1층(생산)\"],\"1767886554527\":[\"소금물\"]}', '2026-03-18 09:24:04'),
(342, '2026-03-16', '생산 현장 업무 회의록', '*장담기 일정 변경\n  - 2026.03.19(목) ~ 2026.03.20(금)\n  - 2호방에 약 200단지 장담기 예정(떡은 5,6,7,8방)\n\n*고철업체 화요일 방문예정\n\n*우 장물빼기 작업', '{\"1767885744947\":[\"고추장\"],\"1767886554527\":[\"소금물\"],\"1767883107605\":[\"사무실\"],\"1767885834789\":[\"사무실\"],\"1767886051326\":[\"사무실\"],\"1768780657172\":[\"사무실\"],\"1767885950539\":[\"1층(생산)\"],\"1767886110985\":[\"1층(생산)\"],\"1767886193864\":[\"1층(생산)\"],\"1767886242826\":[\"1층(생산)\"],\"1767886321944\":[\"1층(생산)\"],\"1767934281326\":[\"1층(생산)\"],\"1767886449701\":[\"2층(콩증자 및 탈분)\"],\"1772497624802\":[\"2층(콩증자 및 탈분)\"],\"1767934110640\":[\"2층(콩증자 및 탈분)\"],\"1767886730545\":[\"2층(콩증자 및 탈분)\"]}', '2026-03-18 09:24:04'),
(343, '2026-03-13', '생산 현장 업무 회의록', '-간장작업 2명(이민여, 에리꼬)\n-월간 콩 삶는 인력 조율\n(작업 부하를 고려한 월간 인력 배치 계획 필요)\n-주말 근무 시 발생하는 외국인들 출퇴근 관련 해결방안 필요\n-고철 구매업자 금일 방문 예정이였으나 현재까지 연락 안되는 상태\n-청송여중 급식용 된장,고추장 배달\n-점심시간 외국인 근로자 묘 카드 현금인출 문제로 13:00 농협방문예정\n-13:00 유리병 입고예정 (광동유리)\n-공장 무선랜 설치작업 보조(오후/김영주)', '{\"1767886449701\":[\"2층(콩증자 및 탈분)\"],\"1767886730545\":[\"2층(콩증자 및 탈분)\"],\"1767934110640\":[\"2층(콩증자 및 탈분)\"],\"1767934281326\":[\"1층(생산)\"],\"1772497624802\":[\"2층(콩증자 및 탈분)\"],\"1767883107605\":[\"사무실\"],\"1768780657172\":[\"사무실\"],\"1767886051326\":[\"사무실\"],\"1767886110985\":[\"1층(생산)\"],\"1767886193864\":[\"1층(생산)\"],\"1767886242826\":[\"1층(생산)\"],\"1767886321944\":[\"간장(송주원)\"],\"1767886554527\":[\"1층(생산)\",\"소금물\"],\"1767885744947\":[\"소금물\"]}', '2026-03-18 09:24:04'),
(344, '2026-03-12', '생산 현장 업무 회의록', '- 쿠팡 맥된장450g 반제품 작업(서울발주 수량 체크 후 일정조율)\n- 금요일 알메주 망 투입 작업(서울발주 수량 체크 후 일정조율)\n- 우는 오전에 생산현장 투입', '{\"1767886449701\":[\"2층(콩증자 및 탈분)\"],\"1772497624802\":[\"2층(콩증자 및 탈분)\"],\"1767934110640\":[\"2층(콩증자 및 탈분)\"],\"1767886730545\":[\"2층(콩증자 및 탈분)\"],\"1767885744947\":[\"고추장\"],\"1767886554527\":[\"소금물\",\"1층(생산)\"],\"1767886110985\":[\"1층(생산)\"],\"1767886193864\":[\"1층(생산)\"],\"1767886242826\":[\"1층(생산)\"],\"1767886321944\":[\"1층(생산)\"],\"1767934281326\":[\"1층(생산)\"]}', '2026-03-18 09:24:04'),
(345, '2026-03-11', '생산 현장 업무 회의록', '- 금일 생산 작업 일정 공유\n- 고철 판매 내용 공유(청송업체 외)\n- 종이 수거 관련 애용 공유\n- 담배꽁초 지정된 철통 내 폐기\n- 오징어 포장용 비닐봉투 구매요청\n- 자재 재고 관리 및 소진 전 공유 체계 강화\n\n▼안전대행업체 점검내용\n-압력용기 안전인증 확인 서류 확보 및 앙카볼트 고정 조치 요망\n-2층 산업로봇 원활한 안전검출 통과를 위한 관련 인증 서류 확보 요망\n-컨베이어벨트 법적 기준에 따른 관련 인증 서류 확보 및 검사 대비 필요\n(컨베이어 벨트는 모터 1.2km 이상, 속도 초당 15cm 이상, 길이10m 이상 중 해당 사항 있으면 검사대상임)\n안전인증서류가 있어야 정기검사를 받을 수 있는데 추후 1~2년 지난 후에 받으려면 판매업체가 폐업하는 경우도 있어서 서류 받는데 어려움이 있음. 미리 안전인증 서류를 확보해둬야 정기검사를 원활하게 받을 수 있음\n\n- 2층 작업시 낙상대비 안전교육 필요하고 전직원들 2층에 문닫아둔 상태로 작업하도록 교육 필요', '{\"1767886449701\":[\"2층(콩증자 및 탈분)\"],\"1772497624802\":[\"2층(콩증자 및 탈분)\"],\"1767934110640\":[\"2층(콩증자 및 탈분)\"],\"1767886110985\":[\"2층(콩증자 및 탈분)\"],\"1767886554527\":[\"가루청국장탈분\",\"소금물\"],\"1767885744947\":[\"소금물\"],\"1767883107605\":[\"사무실\"],\"1768780657172\":[\"사무실\"],\"1767886051326\":[\"사무실\"],\"1767885834789\":[\"사무실\"],\"1767886193864\":[\"항아리(장입출고)\"],\"1767886242826\":[\"항아리(장입출고)\"],\"1767886321944\":[\"항아리(장입출고)\"],\"1767934281326\":[\"항아리(장입출고)\"],\"1767886730545\":[\"항아리(장입출고)\"]}', '2026-03-18 09:24:04'),
(346, '2026-03-10', '생산 현장 업무 회의록', '- 유리병 부족분 발주 진행\n- 깻묵 수거(업체:이로움)\n- 장담기 차주 중 일정조율\n- 작업 과정 중 라벨 부착 및 박스 포장 상태 품질 검수 강화', '{\"1767886449701\":[\"2층(콩증자 및 탈분)\"],\"1772497624802\":[\"2층(콩증자 및 탈분)\"],\"1767934281326\":[\"2층(콩증자 및 탈분)\"],\"1767934110640\":[\"2층(콩증자 및 탈분)\"],\"1767885744947\":[\"소금물\"],\"1767886554527\":[\"소금물\"],\"1767883107605\":[\"사무실\"],\"1768780657172\":[\"사무실\"],\"1767886051326\":[\"사무실\"],\"1767885834789\":[\"사무실\"],\"1767886110985\":[\"1층(생산)\"],\"1767886193864\":[\"1층(생산)\"],\"1767886242826\":[\"1층(생산)\"],\"1767886321944\":[\"1층(생산)\"],\"1767885950539\":[\"1층(생산)\"],\"1767886730545\":[\"1층(생산)\"]}', '2026-03-18 09:24:04'),
(347, '2026-03-09', '생산 현장 업무 회의록', '- 참기름 생산 후 용기 외부에 묻은 참기름 세척.\n- 더덕초무침 작업 라벨작업\n- 1층 생산 현장 인원 부족으로 \'우\'가 소금물 작업과 1층 생산 업무를 실시간 병행하여 공정 공백 최소화.', '{\"1767934110640\":[\"참기름공장\"],\"1772497624802\":[\"2층(콩증자 및 탈분)\"],\"1767886449701\":[\"2층(콩증자 및 탈분)\"],\"1767886242826\":[\"2층(콩증자 및 탈분)\",\"1층(생산)\"],\"1767934281326\":[\"2층(콩증자 및 탈분)\"],\"1767886730545\":[\"1층(생산)\"],\"1767886110985\":[\"1층(생산)\"],\"1767886321944\":[\"1층(생산)\"],\"1767885950539\":[\"1층(생산)\"],\"1767886193864\":[\"1층(생산)\"],\"1767886554527\":[\"소금물\",\"1층(생산)\"],\"1767885744947\":[\"소금물\"],\"1767883107605\":[\"사무실\"],\"1768780657172\":[\"사무실\"],\"1767885834789\":[\"사무실\"],\"1767886051326\":[\"참기름공장\",\"사무실\"]}', '2026-03-18 09:24:04'),
(348, '2026-03-06', '생산 현장 업무 회의록', '주요 논의 안건\n[안건 1] 메주 작업 공정 설비 개선\n현황: 메주 작업 투입 인원 증가 (작년 3명 → 올해 4명)\n요청: 작업 효율성 및 생산성 제고를 위한 설비 개선 필요\n\n[안건 2] 흡입 펌프 부품 교체\n현황: 쌈장 및 고추장 라인 흡입 펌프 고무 부품 불량 발생\n요청: 공정 지연 방지를 위한 신속한 부품 구매 및 교체 진행', '{\"1767885744947\":[\"소금물\",\"가루청국장탈분\"],\"1767886449701\":[\"2층(콩증자 및 탈분)\"],\"1767886730545\":[\"2층(콩증자 및 탈분)\"],\"1772497624802\":[\"2층(콩증자 및 탈분)\"],\"1767886242826\":[\"2층(콩증자 및 탈분)\"],\"1767934281326\":[\"참기름공장\"],\"1767934110640\":[\"참기름공장\"],\"1767886051326\":[\"참기름공장\"],\"1767886110985\":[\"1층(생산)\"],\"1767886193864\":[\"1층(생산)\"],\"1767885950539\":[\"1층(생산)\"],\"1767886554527\":[\"소금물\",\"가루청국장탈분\"],\"1767883107605\":[\"사무실\"],\"1767885834789\":[\"사무실\"],\"1768780657172\":[\"사무실\"]}', '2026-03-18 09:24:04');
